import { loadChalk } from './chalk.js';

/**
 * Format diff output for display
 * @param {import('../types.js').DiffResult} diffResult - Result from comparePdfs or compareTexts
 * @param {import('../types.js').FormatOptions} [options] - Formatting options
 * @returns {Promise<string>} Formatted diff output
 */
export async function formatDiff(diffResult, options = {}) {
  const { showUnchanged = false, context = 3, color = true } = options;
  const { changes, summary, identical } = diffResult;
  
  const chalk = await loadChalk();
  
  if (identical) {
    const checkMark = color ? chalk.green('✓') : '✓';
    return `${checkMark} ${summary}\n`;
  }
  
  const fileIcon = color ? chalk.blue('📄') : '📄';
  let output = `${fileIcon} ${summary}\n\n`;
  
  changes.forEach((change) => {
    if (change.added) {
      const lines = change.value.split('\n');
      lines.forEach(line => {
        if (line.trim()) {
          const prefix = color ? chalk.green('+ ') : '+ ';
          const content = color ? chalk.green(line) : line;
          output += `${prefix}${content}\n`;
        }
      });
    } else if (change.removed) {
      const lines = change.value.split('\n');
      lines.forEach(line => {
        if (line.trim()) {
          const prefix = color ? chalk.red('- ') : '- ';
          const content = color ? chalk.red(line) : line;
          output += `${prefix}${content}\n`;
        }
      });
    } else {
      // Unchanged content - show normally when showUnchanged is true
      if (showUnchanged) {
        const lines = change.value.split('\n');
        if (lines.length > context * 2) {
          // Show first few lines
          for (let i = 0; i < context; i++) {
            if (lines[i]) {
              const content = color ? chalk.dim(`  ${lines[i]}`) : `  ${lines[i]}`;
              output += `${content}\n`;
            }
          }
          const dots = color ? chalk.dim('  ...') : '  ...';
          output += `${dots}\n`;
          // Show last few lines
          for (let i = lines.length - context; i < lines.length; i++) {
            if (lines[i]) {
              const content = color ? chalk.dim(`  ${lines[i]}`) : `  ${lines[i]}`;
              output += `${content}\n`;
            }
          }
        } else {
          lines.forEach(line => {
            if (line) {
              const content = color ? chalk.dim(`  ${line}`) : `  ${line}`;
              output += `${content}\n`;
            }
          });
        }
      }
    }
  });
  
  return output;
}